#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int cnt[11]={0};
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            cnt[x]++;
        }
        int maxc=0, ans=0, tie=0;
        for(int i=1;i<=10;i++){
            if(cnt[i]>maxc){
                maxc=cnt[i]; ans=i; tie=0;
            } else if(cnt[i]==maxc && maxc>0){
                tie=1;
            }
        }
        if(tie) printf("CONFUSED\n");
        else printf("%d\n",ans);
    }
    return 0;
}

