#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        cnt = [0]*11
        for _ in range(N):
            x = next(it)
            cnt[x] += 1
        maxc = 0
        ans = 0
        tie = False
        for i in range(1,11):
            if cnt[i] > maxc:
                maxc = cnt[i]
                ans = i
                tie = False
            elif cnt[i] == maxc and maxc > 0:
                tie = True
        out_lines.append('CONFUSED' if tie else str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

